+import java.lang.ref.ReferenceQueue;
+import java.lang.ref.WeakReference;
+import java.util.Set;
+import java.util.concurrent.ConcurrentHashMap;
+import java.util.concurrent.atomic.AtomicLong;
+
+public final class GenerationTracker {
+    private static final ReferenceQueue<ClassLoader> RECLAIMED_LOADERS = new ReferenceQueue<>();
+    private static final Set<LoaderReference> LIVE_LOADERS = ConcurrentHashMap.newKeySet();
+    private static final AtomicLong TRACKED = new AtomicLong();
+    private static final AtomicLong RECLAIMED = new AtomicLong();
+
+    private GenerationTracker() {
+    }
+
+    public static void track(ClassLoader classLoader) {
+        collect();
+        LIVE_LOADERS.add(new LoaderReference(classLoader, RECLAIMED_LOADERS));
+        TRACKED.incrementAndGet();
+    }
+
+    public static long trackedCount() {
+        collect();
+        return TRACKED.get();
+    }
+
+    public static long reclaimedCount() {
+        collect();
+        return RECLAIMED.get();
+    }
+
+    public static long liveCount() {
+        collect();
+        return LIVE_LOADERS.size();
+    }
+
+    public static void collect() {
+        LoaderReference reference = (LoaderReference) RECLAIMED_LOADERS.poll();
+        while (reference != null) {
+            if (LIVE_LOADERS.remove(reference)) {
+                RECLAIMED.incrementAndGet();
+            }
+            reference = (LoaderReference) RECLAIMED_LOADERS.poll();
+        }
+    }
+
+    private static final class LoaderReference extends WeakReference<ClassLoader> {
+        private LoaderReference(ClassLoader referent, ReferenceQueue<ClassLoader> queue) {
+            super(referent, queue);
+        }
+    }
+}
